const headers = $json.headers || {};
const body = $json.body || {};

const appId = String(body.app_id || '');
const timestampRaw = String(body.timestamp || headers['x-zalo-timestamp'] || headers['X-Zalo-Timestamp'] || '');
const payload = JSON.stringify(body);
const secret = String($env.ZALO_OA_SECRET || '');
const signature = String(headers['x-zalo-signature'] || headers['X-Zalo-Signature'] || '').trim();
const replayWindowSec = Number($env.WEBHOOK_REPLAY_WINDOW_SECONDS || 300);

const senderId = String(body?.sender?.id || body?.sender_id || body?.user_id || '').trim() || 'unknown';
const msgId = String(body?.message?.msg_id || body?.message_id || body?.msg_id || body?.event_id || '').trim();

if (!appId || !timestampRaw || !secret || !signature) {
  return [{ json: { isValid: false, reason: 'missing_signature_fields', sender_id: senderId, zalo_msg_id: msgId || null, payload } }];
}

const timestamp = Number(timestampRaw);
if (!Number.isFinite(timestamp)) {
  return [{ json: { isValid: false, reason: 'invalid_timestamp', sender_id: senderId, zalo_msg_id: msgId || null, payload } }];
}

const nowSec = Math.floor(Date.now() / 1000);
const ageSec = Math.abs(nowSec - timestamp);
if (ageSec > replayWindowSec) {
  return [{ json: { isValid: false, reason: 'timestamp_out_of_window', sender_id: senderId, zalo_msg_id: msgId || null, payload, age_sec: ageSec } }];
}

const crypto = require('crypto');
const expected = crypto.createHash('sha256').update(`${appId}${timestampRaw}${payload}${secret}`, 'utf8').digest('hex');
const provided = signature.toLowerCase();

let ok = false;
try {
  ok = provided.length === expected.length && crypto.timingSafeEqual(Buffer.from(provided, 'utf8'), Buffer.from(expected, 'utf8'));
} catch {
  ok = false;
}

return [{
  json: {
    isValid: ok,
    reason: ok ? null : 'invalid_signature',
    sender_id: senderId,
    zalo_msg_id: msgId || null,
    payload
  }
}];

const record = $json;
if (!record?.access_token || !record?.expires_at) {
  throw new Error('E011: Zalo access token expired or missing. Check Phase 0.5 workflow.');
}

const expiresAt = new Date(record.expires_at);
if (Number.isNaN(expiresAt.getTime()) || expiresAt <= new Date()) {
  throw new Error('E011: Zalo access token expired or missing. Check Phase 0.5 workflow.');
}

const senderId = $('Mark Replay State').item.json.sender_id;
if (!senderId || senderId === 'unknown') {
  return [{ json: { skip: true, reason: 'no_sender_id' } }];
}

return [{
  json: {
    skip: false,
    access_token: record.access_token,
    request_body: {
      recipient: { user_id: senderId },
      message: { text: 'Sếp ơi, em nhận được tin nhắn rồi!' }
    }
  }
}];

const current = $('Verify Signature Async').item.json;
if (!current.zalo_msg_id) return [{ json: { ...current, replayed: false } }];
const row = $json || {};
return [{ json: { ...current, replayed: !!row.id, replay_row_id: row.id || null } }];
